-- Functions
CREATE OR REPLACE FUNCTION public.calculate_user_level(points integer)
 RETURNS character varying
 LANGUAGE plpgsql
AS $function$
BEGIN
    CASE
        WHEN points >= 5000 THEN RETURN 'Master';
        WHEN points >= 3000 THEN RETURN 'Expert';
        WHEN points >= 1500 THEN RETURN 'Advanced';
        WHEN points >= 500 THEN RETURN 'Intermediate';
        ELSE RETURN 'Beginner';
    END CASE;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.cleanup_friendship_on_status_change()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
    -- If a friend request is cancelled or deleted, remove the friendship
    IF (OLD.status = 'accepted' AND NEW.status IN ('cancelled', 'rejected')) OR TG_OP = 'DELETE' THEN
        DELETE FROM friendships
        WHERE (user1_id = LEAST(OLD.requester_id, OLD.requested_id)
               AND user2_id = GREATEST(OLD.requester_id, OLD.requested_id));
    END IF;

    IF TG_OP = 'DELETE' THEN
        RETURN OLD;
    END IF;
    RETURN NEW;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.create_challenge_notification()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
    -- Create notification for new challenge
    IF TG_OP = 'INSERT' THEN
        INSERT INTO friend_notifications (user_id, type, title, message, related_user_id, created_at)
        SELECT
            NEW.challenged_id,
            'challenge_received',
            'New Challenge Received',
            u.name || ' challenged you to a quiz!',
            NEW.challenger_id,
            CURRENT_TIMESTAMP
        FROM users u WHERE u.id = NEW.challenger_id;

        RETURN NEW;
    END IF;

    -- Create notification for challenge status changes
    IF TG_OP = 'UPDATE' THEN
        -- Challenge accepted
        IF NEW.status = 'accepted' AND OLD.status = 'pending' THEN
            INSERT INTO friend_notifications (user_id, type, title, message, related_user_id, created_at)
            SELECT
                NEW.challenger_id,
                'challenge_accepted',
                'Challenge Accepted',
                u.name || ' accepted your challenge!',
                NEW.challenged_id,
                CURRENT_TIMESTAMP
            FROM users u WHERE u.id = NEW.challenged_id;
        END IF;

        -- Challenge declined
        IF NEW.status = 'declined' AND OLD.status = 'pending' THEN
            INSERT INTO friend_notifications (user_id, type, title, message, related_user_id, created_at)
            SELECT
                NEW.challenger_id,
                'challenge_declined',
                'Challenge Declined',
                u.name || ' declined your challenge.',
                NEW.challenged_id,
                CURRENT_TIMESTAMP
            FROM users u WHERE u.id = NEW.challenged_id;
        END IF;

        -- Challenge completed
        IF NEW.status = 'completed' AND OLD.status = 'accepted' THEN
            -- Determine winner and create notifications for both users
            DECLARE
                winner_id UUID;
                winner_name TEXT;
                loser_id UUID;
            BEGIN
                -- Determine winner
                IF NEW.challenger_score > NEW.challenged_score THEN
                    winner_id := NEW.challenger_id;
                    loser_id := NEW.challenged_id;
                ELSIF NEW.challenged_score > NEW.challenger_score THEN
                    winner_id := NEW.challenged_id;
                    loser_id := NEW.challenger_id;
                END IF;

                -- Create completion notification for challenger
                INSERT INTO friend_notifications (user_id, type, title, message, related_user_id, created_at)
                SELECT
                    NEW.challenger_id,
                    'challenge_completed',
                    'Challenge Completed',
                    CASE
                        WHEN NEW.challenger_score > NEW.challenged_score THEN 'You won the challenge against ' || u.name || '!'
                        WHEN NEW.challenger_score < NEW.challenged_score THEN 'You lost the challenge against ' || u.name || '.'
                        ELSE 'Your challenge with ' || u.name || ' ended in a tie!'
                    END,
                    NEW.challenged_id,
                    CURRENT_TIMESTAMP
                FROM users u WHERE u.id = NEW.challenged_id;

                -- Create completion notification for challenged user
                INSERT INTO friend_notifications (user_id, type, title, message, related_user_id, created_at)
                SELECT
                    NEW.challenged_id,
                    'challenge_completed',
                    'Challenge Completed',
                    CASE
                        WHEN NEW.challenged_score > NEW.challenger_score THEN 'You won the challenge against ' || u.name || '!'
                        WHEN NEW.challenged_score < NEW.challenger_score THEN 'You lost the challenge against ' || u.name || '.'
                        ELSE 'Your challenge with ' || u.name || ' ended in a tie!'
                    END,
                    NEW.challenger_id,
                    CURRENT_TIMESTAMP
                FROM users u WHERE u.id = NEW.challenger_id;
            END;
        END IF;

        RETURN NEW;
    END IF;

    RETURN NULL;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.create_friend_request_notification()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
    INSERT INTO friend_notifications (user_id, type, title, message, related_user_id, friend_request_id, created_at)
    SELECT
        NEW.requested_id,
        'friend_request',
        'New Friend Request',
        u.name || ' sent you a friend request!',
        NEW.requester_id,
        NEW.id,
        CURRENT_TIMESTAMP
    FROM users u WHERE u.id = NEW.requester_id;

    RETURN NEW;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.create_friendship_on_accept()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
    -- Only create friendship if status changed to 'accepted'
    IF NEW.status = 'accepted' AND OLD.status != 'accepted' THEN
        -- Ensure user1_id < user2_id for consistent ordering
        INSERT INTO friendships (user1_id, user2_id, created_at)
        VALUES (
            LEAST(NEW.requester_id, NEW.requested_id),
            GREATEST(NEW.requester_id, NEW.requested_id),
            CURRENT_TIMESTAMP
        )
        ON CONFLICT (user1_id, user2_id) DO NOTHING;

        -- Update responded_at timestamp
        NEW.responded_at = CURRENT_TIMESTAMP;

        -- Create notification for requester
        INSERT INTO friend_notifications (user_id, type, title, message, related_user_id, friend_request_id, created_at)
        SELECT
            NEW.requester_id,
            'friend_accepted',
            'Friend Request Accepted',
            u.name || ' accepted your friend request!',
            NEW.requested_id,
            NEW.id,
            CURRENT_TIMESTAMP
        FROM users u WHERE u.id = NEW.requested_id;
    END IF;

    -- Create notification for rejection
    IF NEW.status = 'rejected' AND OLD.status != 'rejected' THEN
        NEW.responded_at = CURRENT_TIMESTAMP;

        INSERT INTO friend_notifications (user_id, type, title, message, related_user_id, friend_request_id, created_at)
        SELECT
            NEW.requester_id,
            'friend_rejected',
            'Friend Request Declined',
            u.name || ' declined your friend request.',
            NEW.requested_id,
            NEW.id,
            CURRENT_TIMESTAMP
        FROM users u WHERE u.id = NEW.requested_id;
    END IF;

    RETURN NEW;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.expire_challenges()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
    -- Auto-expire challenges that are past their expiry date
    UPDATE challenges
    SET status = 'expired', updated_at = CURRENT_TIMESTAMP
    WHERE expires_at < CURRENT_TIMESTAMP
    AND status IN ('pending', 'accepted');

    RETURN NULL;
END;
$function$
;

