CREATE OR REPLACE FUNCTION public.update_user_level()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
    -- Update level based on new total_points
    NEW.level = calculate_user_level(NEW.total_points);
    RETURN NEW;
END;
$function$
;

