-- Tables
CREATE TABLE achievements (
    id UUID NOT NULL DEFAULT uuid_generate_v4(),
    key VARCHAR(100) NOT NULL,
    title VARCHAR(255) NOT NULL,
    description TEXT NOT NULL,
    icon VARCHAR(100),
    color VARCHAR(50) DEFAULT '#FFD700'::character varying,
    points_reward INTEGER DEFAULT 0,
    category VARCHAR(50) NOT NULL DEFAULT 'general'::character varying,
    is_rare BOOLEAN DEFAULT false,
    is_active BOOLEAN DEFAULT true,
    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
    updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
    UNIQUE (key),
    PRIMARY KEY (id)
);
CREATE TABLE app_settings (
    key VARCHAR(100) NOT NULL,
    value TEXT,
    description TEXT,
    updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
    PRIMARY KEY (key)
);
CREATE TABLE challenges (
    id UUID NOT NULL DEFAULT uuid_generate_v4(),
    challenger_id UUID NOT NULL,
    challenged_id UUID NOT NULL,
    quiz_id UUID NOT NULL,
    status VARCHAR(20) NOT NULL DEFAULT 'pending'::character varying,
    challenger_score DECIMAL,
    challenged_score DECIMAL,
    message TEXT,
    expires_at TIMESTAMP,
    is_group_challenge BOOLEAN DEFAULT false,
    participant_ids _UUID,
    participant_scores JSONB,
    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
    updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
    FOREIGN KEY (challenged_id) REFERENCES users(id) ON DELETE CASCADE,
    FOREIGN KEY (challenger_id) REFERENCES users(id) ON DELETE CASCADE,
    CHECK ((challenger_id <> challenged_id)),
    PRIMARY KEY (id),
    FOREIGN KEY (quiz_id) REFERENCES quizzes(id) ON DELETE CASCADE,
    CHECK (((status)::text = ANY ((ARRAY['pending'::character varying, 'accepted'::character varying, 'completed'::character varying, 'expired'::character varying, 'declined'::character varying])::text[])))
);
CREATE TABLE difficulty_levels (
    id VARCHAR(50) NOT NULL,
    name VARCHAR(255) NOT NULL,
    description TEXT,
    icon_name VARCHAR(100),
    background_color_hex VARCHAR(7),
    PRIMARY KEY (id)
);
CREATE TABLE friend_notifications (
    id UUID NOT NULL DEFAULT uuid_generate_v4(),
    user_id UUID NOT NULL,
    type VARCHAR(50) NOT NULL,
    title VARCHAR(255) NOT NULL,
    message TEXT,
    related_user_id UUID,
    friend_request_id UUID,
    is_read BOOLEAN DEFAULT false,
    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
    read_at TIMESTAMP,
    FOREIGN KEY (friend_request_id) REFERENCES friend_requests(id) ON DELETE CASCADE,
    PRIMARY KEY (id),
    FOREIGN KEY (related_user_id) REFERENCES users(id) ON DELETE CASCADE,
    CHECK (((type)::text = ANY ((ARRAY['friend_request'::character varying, 'friend_accepted'::character varying, 'friend_rejected'::character varying, 'challenge_received'::character varying, 'challenge_accepted'::character varying, 'challenge_declined'::character varying, 'challenge_completed'::character varying])::text[]))),
    FOREIGN KEY (user_id) REFERENCES users(id) ON DELETE CASCADE
);
CREATE TABLE friend_requests (
    id UUID NOT NULL DEFAULT uuid_generate_v4(),
    requester_id UUID NOT NULL,
    requested_id UUID NOT NULL,
    status VARCHAR(20) NOT NULL DEFAULT 'pending'::character varying,
    message TEXT,
    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
    responded_at TIMESTAMP,
    CHECK ((requester_id <> requested_id)),
    PRIMARY KEY (id),
    FOREIGN KEY (requested_id) REFERENCES users(id) ON DELETE CASCADE,
    FOREIGN KEY (requester_id) REFERENCES users(id) ON DELETE CASCADE,
    UNIQUE (requester_id, requested_id),
    CHECK (((status)::text = ANY ((ARRAY['pending'::character varying, 'accepted'::character varying, 'rejected'::character varying, 'cancelled'::character varying])::text[])))
);
CREATE TABLE friendships (
    id UUID NOT NULL DEFAULT uuid_generate_v4(),
    user1_id UUID NOT NULL,
    user2_id UUID NOT NULL,
    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
    CHECK ((user1_id <> user2_id)),
    CHECK ((user1_id < user2_id)),
    PRIMARY KEY (id),
    FOREIGN KEY (user1_id) REFERENCES users(id) ON DELETE CASCADE,
    UNIQUE (user1_id, user2_id),
    FOREIGN KEY (user2_id) REFERENCES users(id) ON DELETE CASCADE
);
CREATE TABLE interests (
    id VARCHAR(50) NOT NULL,
    name VARCHAR(255) NOT NULL,
    description TEXT,
    icon_name VARCHAR(100),
    color_hex VARCHAR(7),
    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
    PRIMARY KEY (id)
);
CREATE TABLE leaderboard_snapshots (
    id UUID NOT NULL DEFAULT uuid_generate_v4(),
    user_id UUID,
    snapshot_date DATE NOT NULL,
    period_type VARCHAR(20) NOT NULL,
    rank_position INTEGER NOT NULL,
    total_points INTEGER NOT NULL,
    quizzes_completed INTEGER NOT NULL,
    average_score DECIMAL NOT NULL,
    current_streak INTEGER NOT NULL,
    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
    PRIMARY KEY (id),
    FOREIGN KEY (user_id) REFERENCES users(id) ON DELETE CASCADE,
    UNIQUE (user_id, snapshot_date, period_type)
);
CREATE TABLE notification_frequencies (
    id VARCHAR(50) NOT NULL,
    name VARCHAR(255) NOT NULL,
    description TEXT,
    icon_name VARCHAR(100),
    PRIMARY KEY (id)
);
CREATE TABLE questions (
    id UUID NOT NULL DEFAULT uuid_generate_v4(),
    quiz_id UUID,
    question_text TEXT NOT NULL,
    question_type VARCHAR(50) NOT NULL,
    options TEXT[],
    correct_answer TEXT NOT NULL,
    explanation TEXT,
    order_index INTEGER NOT NULL,
    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
    PRIMARY KEY (id),
    FOREIGN KEY (quiz_id) REFERENCES quizzes(id) ON DELETE CASCADE
);
CREATE TABLE quiz_attempts (
    id UUID NOT NULL DEFAULT uuid_generate_v4(),
    quiz_id UUID,
    user_id UUID,
    score DECIMAL NOT NULL,
    total_points INTEGER NOT NULL,
    time_spent INTEGER NOT NULL,
    is_completed BOOLEAN DEFAULT false,
    started_at TIMESTAMP NOT NULL,
    completed_at TIMESTAMP,
    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
    updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
    PRIMARY KEY (id),
    FOREIGN KEY (quiz_id) REFERENCES quizzes(id) ON DELETE CASCADE,
    FOREIGN KEY (user_id) REFERENCES users(id) ON DELETE CASCADE
);
CREATE TABLE quiz_ratings (
    id UUID NOT NULL DEFAULT uuid_generate_v4(),
    user_id UUID,
    quiz_id UUID,
    rating INTEGER,
    review TEXT,
    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
    PRIMARY KEY (id),
    FOREIGN KEY (quiz_id) REFERENCES quizzes(id) ON DELETE CASCADE,
    CHECK (((rating >= 1) AND (rating <= 5))),
    FOREIGN KEY (user_id) REFERENCES users(id) ON DELETE CASCADE,
    UNIQUE (user_id, quiz_id)
);
CREATE TABLE quiz_statistics (
    quiz_id UUID NOT NULL,
    total_attempts INTEGER DEFAULT 0,
    total_completions INTEGER DEFAULT 0,
    average_score DECIMAL DEFAULT 0.0,
    average_time_seconds INTEGER DEFAULT 0,
    difficulty_rating DECIMAL DEFAULT 0.0,
    popularity_score INTEGER DEFAULT 0,
    last_updated TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
    PRIMARY KEY (quiz_id),
    FOREIGN KEY (quiz_id) REFERENCES quizzes(id) ON DELETE CASCADE
);
CREATE TABLE quizzes (
    id UUID NOT NULL DEFAULT uuid_generate_v4(),
    title VARCHAR(500) NOT NULL,
    description TEXT,
    category_id VARCHAR(50),
    difficulty VARCHAR(50),
    article_summary TEXT,
    total_questions INTEGER NOT NULL,
    time_limit_minutes INTEGER NOT NULL,
    points INTEGER NOT NULL,
    is_featured BOOLEAN DEFAULT false,
    is_active BOOLEAN DEFAULT true,
    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
    updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
    created_by UUID,
    is_public BOOLEAN DEFAULT true,
    tags TEXT[] DEFAULT '{}'::text[],
    thumbnail_url VARCHAR(500),
    FOREIGN KEY (category_id) REFERENCES interests(id),
    FOREIGN KEY (created_by) REFERENCES users(id),
    FOREIGN KEY (difficulty) REFERENCES difficulty_levels(id),
    PRIMARY KEY (id)
);
CREATE TABLE refresh_tokens (
    id UUID NOT NULL DEFAULT uuid_generate_v4(),
    user_id UUID NOT NULL,
    token VARCHAR(500) NOT NULL,
    expires_at TIMESTAMP WITH TIME ZONE NOT NULL,
    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
    PRIMARY KEY (id),
    UNIQUE (token),
    FOREIGN KEY (user_id) REFERENCES users(id) ON DELETE CASCADE
);
CREATE TABLE user_achievements (
    id UUID NOT NULL DEFAULT uuid_generate_v4(),
    user_id UUID,
    achievement_id UUID,
    unlocked_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
    points_awarded INTEGER DEFAULT 0,
    FOREIGN KEY (achievement_id) REFERENCES achievements(id) ON DELETE CASCADE,
    PRIMARY KEY (id),
    UNIQUE (user_id, achievement_id),
    FOREIGN KEY (user_id) REFERENCES users(id) ON DELETE CASCADE
);
CREATE TABLE user_category_performance (
    id UUID NOT NULL DEFAULT uuid_generate_v4(),
    user_id UUID,
    category_id VARCHAR(100) NOT NULL,
    category_name VARCHAR(255) NOT NULL,
    total_points INTEGER DEFAULT 0,
    quizzes_completed INTEGER DEFAULT 0,
    average_score DECIMAL DEFAULT 0.0,
    best_score DECIMAL DEFAULT 0.0,
    last_attempt_at TIMESTAMP,
    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
    updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
    PRIMARY KEY (id),
    UNIQUE (user_id, category_id),
    FOREIGN KEY (user_id) REFERENCES users(id) ON DELETE CASCADE
);
CREATE TABLE user_preferences (
    id UUID NOT NULL DEFAULT uuid_generate_v4(),
    user_id UUID,
    selected_interests TEXT[],
    difficulty_preference VARCHAR(50),
    notifications_enabled BOOLEAN DEFAULT true,
    notification_frequency VARCHAR(50),
    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
    PRIMARY KEY (id),
    FOREIGN KEY (user_id) REFERENCES users(id) ON DELETE CASCADE
);
CREATE TABLE user_quiz_favorites (
    id UUID NOT NULL DEFAULT uuid_generate_v4(),
    user_id UUID,
    quiz_id UUID,
    favorited_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
    PRIMARY KEY (id),
    FOREIGN KEY (quiz_id) REFERENCES quizzes(id) ON DELETE CASCADE,
    FOREIGN KEY (user_id) REFERENCES users(id) ON DELETE CASCADE,
    UNIQUE (user_id, quiz_id)
);
CREATE TABLE user_rank_history (
    id UUID NOT NULL DEFAULT uuid_generate_v4(),
    user_id UUID,
    period_type VARCHAR(20) NOT NULL,
    old_rank INTEGER,
    new_rank INTEGER NOT NULL,
    rank_change INTEGER NOT NULL DEFAULT 0,
    points_at_change INTEGER NOT NULL,
    changed_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
    PRIMARY KEY (id),
    FOREIGN KEY (user_id) REFERENCES users(id) ON DELETE CASCADE
);
CREATE TABLE users (
    id UUID NOT NULL DEFAULT uuid_generate_v4(),
    email VARCHAR(255) NOT NULL,
    name VARCHAR(255) NOT NULL,
    age INTEGER,
    password_hash VARCHAR(255) NOT NULL,
    level VARCHAR(50) DEFAULT 'Beginner'::character varying,
    total_points INTEGER DEFAULT 0,
    current_streak INTEGER DEFAULT 0,
    best_streak INTEGER DEFAULT 0,
    total_quizzes_completed INTEGER DEFAULT 0,
    average_score DECIMAL DEFAULT 0.0,
    is_online BOOLEAN DEFAULT false,
    last_active TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
    avatar_url VARCHAR(500),
    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
    updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
    UNIQUE (email),
    PRIMARY KEY (id)
);
